import React, { useState, useRef } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import './Navbar.css';

const Navbar = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const dropdownRef = useRef(null);
  
  const [showNotifications, setShowNotifications] = useState(false);

  // Check if user is customer
  const isCustomer = user?.role === 'customer';
  
  // HARDCODED NOTIFICATIONS - ONLY FOR CUSTOMERS
  const notifications = [
    {
      id: 1,
      title: '👋 Welcome to AgriVend!',
      message: 'Thank you for being a valued customer.',
      icon: '🎉',
      color: '#10b981',
      link: '/customer/dashboard',
      time: new Date().toISOString()
    },
    {
      id: 2,
      title: '⭐ Admin replied to your rating',
      message: 'Thank you for your feedback!',
      icon: '⭐',
      color: '#f59e0b',
      link: '/customer/ratings',
      time: new Date().toISOString()
    },
    {
      id: 3,
      title: '💬 New message reply',
      message: 'Admin responded to your support ticket.',
      icon: '💬',
      color: '#3b82f6',
      link: '/customer/messages',
      time: new Date().toISOString()
    }
  ];

  const unreadCount = isCustomer ? 3 : 0; // Only show count for customers

  const handleNotificationClick = (link) => {
    setShowNotifications(false);
    if (link) navigate(link);
  };

  // If not logged in, don't show navbar
  if (!user) return null;

  return (
    <nav className="navbar">
      <div className="navbar-container">
        <Link to="/" className="navbar-logo">
          <span className="logo-icon">🌾</span>
          <span className="logo-text">AgriVend</span>
        </Link>

        <div className="navbar-actions">
          {/* Notifications Bell - ONLY SHOW FOR CUSTOMERS */}
          {isCustomer && (
            <div className="notification-wrapper" ref={dropdownRef}>
              <button 
                className="notification-btn"
                onClick={() => setShowNotifications(!showNotifications)}
              >
                <span className="notification-icon">🔔</span>
                <span className="notification-badge">{unreadCount}</span>
              </button>

              {/* Notifications Dropdown */}
              {showNotifications && (
                <div className="notifications-dropdown">
                  <div className="notifications-header">
                    <h3>Notifications</h3>
                    <span className="notification-count">{unreadCount} new</span>
                  </div>

                  <div className="notifications-list">
                    {notifications.map((notif) => (
                      <div
                        key={notif.id}
                        className="notification-item unread"
                        onClick={() => handleNotificationClick(notif.link)}
                      >
                        <div 
                          className="notification-icon-wrapper"
                          style={{ backgroundColor: notif.color + '20' }}
                        >
                          <span style={{ color: notif.color }}>{notif.icon}</span>
                        </div>
                        <div className="notification-content">
                          <div className="notification-title">{notif.title}</div>
                          <div className="notification-message">{notif.message}</div>
                          <div className="notification-time">Just now</div>
                        </div>
                        <span className="unread-dot" />
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          )}

          {/* User Menu - Shows for EVERYONE */}
          <div className="user-menu">
            <span className="user-name">
              {user?.firstName} {user?.lastName}
            </span>
            <span className="user-role">
              ({user?.role === 'admin' ? 'Admin' : 'Customer'})
            </span>
            <button onClick={logout} className="logout-btn-nav">
              Logout
            </button>
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
